// Cache metadata
export const cacheInfo = {
  version: cache.version || 1,
  lastUpdated: cache.lastUpdated || null,
  totalProviders: cache.providers.length,
  verifiedCount: cache.providers.filter(p => p.greenVerified).length,
  unverifiedCount: cache.providers.filter(p => !p.greenVerified).length,
};